}if(jQuery("#uc_scroll_accordion_elementor_68392b2").length && !jQuery("#uc_scroll_accordion_elementor_68392b2").parents('[data-elementor-type="popup"]').length) uc_scroll_accordion_elementor_68392b2_start();
	jQuery( document ).on( 'elementor/popup/show', (event, id, objPopup) => {
